#usda 1.0
(
    defaultPrim = "Assets"
)

def Xform "Assets"
{
    def Xform "Chair" (
        variants = {
            string modelVariant = "detailed"
        }
        prepend variantSets = "modelVariant"
    )
    {
        variantSet "modelVariant" = {
            "detailed" {
                def Mesh "Geo"
                {
                    int[] faceVertexCounts = [4, 4, 4, 4, 4, 4]
                    int[] faceVertexIndices = [0, 1, 2, 3, 4, 5, 6, 7, 0, 1, 5, 4, 2, 3, 7, 6, 0, 3, 7, 4, 1, 2, 6, 5]
                    point3f[] points = [(-0.5, 0, -0.5), (0.5, 0, -0.5), (0.5, 0, 0.5), (-0.5, 0, 0.5), (-0.5, 1, -0.5), (0.5, 1, -0.5), (0.5, 1, 0.5), (-0.5, 1, 0.5)]
                }

            }
            "simple" {
                def Mesh "Geo"
                {
                    int[] faceVertexCounts = [4, 4, 4, 4, 4, 4]
                    int[] faceVertexIndices = [0, 1, 2, 3, 4, 5, 6, 7, 0, 1, 5, 4, 2, 3, 7, 6, 0, 3, 7, 4, 1, 2, 6, 5]
                    point3f[] points = [(-0.5, 0, -0.5), (0.5, 0, -0.5), (0.5, 0, 0.5), (-0.5, 0, 0.5), (-0.5, 1, -0.5), (0.5, 1, -0.5), (0.5, 1, 0.5), (-0.5, 1, 0.5)]
                }

            }
        }
    }
}

#usda 1.0
(
    defaultPrim = "Shot"
    subLayers = [
        @assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA" (
            prepend references = @assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (-2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }

        def Xform "ChairB" (
            prepend references = @assets.usda@</Assets/Chair>
        )
        {
            double3 xformOp:translate = (2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "night"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        variantSet "lightingVariant" = {
            "day" {
                def DistantLight "Sun"
                {
                    float inputs:intensity = 50000
                }

            }
            "night" {
                def DomeLight "Sky"
                {
                    float inputs:intensity = 500
                }

            }
        }
    }
}
